@page "/account/login"
@using Microsoft.AspNetCore.Identity

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h3>Login</h3>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <form method="post" @formname="login" @onsubmit="HandleLogin">
            <AntiforgeryToken />
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="email" required />
            </div>
            <div class="mb-3">
                <label class="form-label">Password</label>
                <input type="password" class="form-control" @bind="password" required />
            </div>
            <button type="submit" class="btn btn-primary w-100">Sign In</button>
        </form>
    </div>
</div>

@code {
    [Inject] private SignInManager<IdentityUser> SignInManager { get; set; } = default!;
    [Inject] private NavigationManager Navigation { get; set; } = default!;

    [SupplyParameterFromQuery] private string? returnUrl { get; set; }

    private string email = "";
    private string password = "";
    private string? errorMessage;

    private async Task HandleLogin()
    {
        var result = await SignInManager.PasswordSignInAsync(email, password, isPersistent: false, lockoutOnFailure: false);
        if (result.Succeeded)
        {
            Navigation.NavigateTo(returnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }
}

@page "/account/logout"
@using Microsoft.AspNetCore.Identity

<PageTitle>Logging out…</PageTitle>

@code {
    [Inject] private SignInManager<IdentityUser> SignInManager { get; set; } = default!;
    [Inject] private NavigationManager Navigation { get; set; } = default!;

    protected override async Task OnInitializedAsync()
    {
        await SignInManager.SignOutAsync();
        Navigation.NavigateTo("/account/login", forceLoad: true);
    }
}

@page "/admin/users"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@attribute [Authorize(Roles = "Admin")]

<PageTitle>User Management</PageTitle>

<h3>User Management</h3>

@if (userRoles is null)
{
    <p><em>Loading…</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var entry in userRoles)
            {
                <tr>
                    <td>@entry.Email</td>
                    <td>@string.Join(", ", entry.Roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Inject] private UserManager<IdentityUser> UserManager { get; set; } = default!;

    private List<UserWithRoles>? userRoles;

    protected override async Task OnInitializedAsync()
    {
        var users = UserManager.Users.ToList();
        userRoles = [];
        foreach (var user in users)
        {
            var roles = await UserManager.GetRolesAsync(user);
            userRoles.Add(new UserWithRoles(user.Email!, roles));
        }
    }

    private record UserWithRoles(string Email, IList<string> Roles);
}

@page "/directory"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]

<PageTitle>Employee Directory</PageTitle>

<h3>Employee Directory</h3>

<table class="table table-striped">
    <thead>
        <tr>
            <th>Name</th>
            <th>Department</th>
            <th>Email</th>
            <th>Extension</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var emp in employees)
        {
            <tr>
                <td>@emp.Name</td>
                <td>@emp.Department</td>
                <td>@emp.Email</td>
                <td>@emp.Extension</td>
            </tr>
        }
    </tbody>
</table>

@code {
    private readonly List<Employee> employees =
    [
        new("Alice Johnson", "Engineering", "alice@company.com", "x1001"),
        new("Bob Smith", "Marketing", "bob@company.com", "x1002"),
        new("Carol Davis", "Human Resources", "carol@company.com", "x1003"),
        new("Dan Wilson", "Finance", "dan@company.com", "x1004"),
        new("Eve Martinez", "Engineering", "eve@company.com", "x1005")
    ];

    private record Employee(string Name, string Department, string Email, string Extension);
}

